Функция ПолучитьСуммарныйДолгКонтрагента(Контрагент)
	Если Не ЗначениеЗаполнено(Контрагент) Тогда
		Возврат 0;
	КонецЕсли;

	Запрос = Новый Запрос;
	Запрос.Текст =
	"ВЫБРАТЬ
		Договоры.Ссылка КАК Договор,
		СУММА(Взаиморасчеты.Сумма) КАК Сумма
	ИЗ
		РегистрНакопления.Взаиморасчеты КАК Взаиморасчеты
		ВНУТРЕННЕЕ СОЕДИНЕНИЕ Справочник.Договоры КАК Договоры
		ПО Взаиморасчеты.Договор = Договоры.Ссылка
	ГДЕ
		Договоры.Владелец = &Контрагент
	СГРУППИРОВАТЬ ПО
		Договоры.Ссылка";

	Запрос.УстановитьПараметр("Контрагент", Контрагент);
	Результат = Запрос.Выполнить();
	Выборка = Результат.Выбрать();

	СуммаДолга = 0;

	Пока Выборка.Следующий() Цикл
		Если ЗначениеЗаполнено(Выборка.Сумма) И Выборка.Сумма > 0 Тогда
			СуммаДолга = СуммаДолга + Выборка.Сумма;
		КонецЕсли;
	КонецЦикла;

	Возврат СуммаДолга;
КонецФункции
